(function () {
  var PATCH_ID = 'fix-sender-avatar-initials-v1';
  if (window['__semai_patch_' + PATCH_ID]) return;
  window['__semai_patch_' + PATCH_ID] = true;

  function getCorrectInitials(displayName) {
    if (!displayName) return '';
    var name = displayName.replace(/^From:\s*/i, '').trim();
    var commaIdx = name.indexOf(',');
    if (commaIdx !== -1) {
      var lastName = name.substring(0, commaIdx).trim();
      var rest = name.substring(commaIdx + 1).trim();
      var firstNamePart = rest.split(/\s+/)[0];
      var firstInitial = firstNamePart ? firstNamePart.charAt(0).toUpperCase() : '';
      var lastInitial = lastName ? lastName.charAt(0).toUpperCase() : '';
      if (firstInitial && lastInitial) return firstInitial + lastInitial;
      return firstInitial || lastInitial;
    }
    var parts = name.split(/\s+/).filter(function(p){ return p.length > 0; });
    if (parts.length >= 2) return parts[0].charAt(0).toUpperCase() + parts[parts.length - 1].charAt(0).toUpperCase();
    if (parts.length === 1) return parts[0].charAt(0).toUpperCase();
    return '';
  }

  function fixAvatar(avatarEl) {
    var label = avatarEl.getAttribute('aria-label') || '';
    var correct = getCorrectInitials(label);
    if (!correct) return;
    var initialsEl = avatarEl.querySelector('.fui-Avatar__initials');
    if (!initialsEl) return;
    var current = initialsEl.textContent.trim();
    if (current !== correct) {
      initialsEl.textContent = correct;
    }
  }

  function fixAll() {
    var avatars = document.querySelectorAll('.semai-chat-avatar, .fui-Avatar');
    for (var i = 0; i < avatars.length; i++) {
      fixAvatar(avatars[i]);
    }
  }

  fixAll();

  var observer = new MutationObserver(function(mutations) {
    for (var i = 0; i < mutations.length; i++) {
      var added = mutations[i].addedNodes;
      for (var j = 0; j < added.length; j++) {
        var node = added[j];
        if (!(node instanceof Element)) continue;
        if (node.matches('.semai-chat-avatar, .fui-Avatar')) {
          fixAvatar(node);
        }
        var nested = node.querySelectorAll('.semai-chat-avatar, .fui-Avatar');
        for (var k = 0; k < nested.length; k++) {
          fixAvatar(nested[k]);
        }
      }
    }
  });
  observer.observe(document.body || document.documentElement, { childList: true, subtree: true });
}());
